package comp310.tests.hw01;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

import java.awt.Color;
import java.awt.Graphics;
import java.awt.image.BufferedImage;
import java.lang.reflect.Field;

import hw01.shape.AShape;
import hw01.shape.Rectangle;
import hw01.shape.Ellipse;
import hw01.shape.Circle;
import hw01.shape.CompositeShape;
import hw01.shape.ASimpleShape;

/**
 * Agent tests to verify that implementation is correct and complete.
 */
class AgentShapeTest {

    private Graphics getGraphics() {
        return new BufferedImage(10, 10, BufferedImage.TYPE_INT_ARGB).createGraphics();
    }

    /**
     * Test setColor on ASimpleShape.
     */
    @Test
    void testASimpleShapeSetColor() throws Exception {
        Rectangle r = new Rectangle(0, 0, 10, 10, Color.RED);
        r.setColor(Color.BLUE);

        // Use reflection to access the protected color field
        Field colorField = ASimpleShape.class.getDeclaredField("color");
        colorField.setAccessible(true);
        Color actualColor = (Color) colorField.get(r);

        assertEquals(Color.BLUE, actualColor, "ASimpleShape.setColor should set the color field");
    }

    /**
     * Test setColor on CompositeShape.
     */
    @Test
    void testCompositeShapeSetColorDelegation() throws Exception {
        Rectangle r = new Rectangle(0, 0, 10, 10, Color.RED);
        Ellipse e = new Ellipse(5, 5, 10, 10, Color.GREEN);
        CompositeShape composite = new CompositeShape(r, e);

        composite.setColor(Color.BLUE);

        Field colorField = ASimpleShape.class.getDeclaredField("color");
        colorField.setAccessible(true);

        Color rColor = (Color) colorField.get(r);
        Color eColor = (Color) colorField.get(e);

        assertEquals(Color.BLUE, rColor, "CompositeShape.setColor should delegate to child 1");
        assertEquals(Color.BLUE, eColor, "CompositeShape.setColor should delegate to child 2");
    }

    /**
     * Test paint on CompositeShape.
     * We'll use a dummy Graphics object and just ensure it doesn't throw.
     * Since we can't easily verify calls to Graphics without a mock framework,
     * we'll stick to basic behavioral tests.
     */
    @Test
    void testCompositeShapePaint() {
        Rectangle r = new Rectangle(0, 0, 10, 10, Color.RED);
        Ellipse e = new Ellipse(5, 5, 10, 10, Color.GREEN);
        CompositeShape composite = new CompositeShape(r, e);

        Graphics g = getGraphics();
        assertDoesNotThrow(() -> composite.paint(g), "CompositeShape.paint should not throw");
    }

    /**
     * Test Circle construction.
     */
    @Test
    void testCircleIsCorrect() throws Exception {
        Circle c = new Circle(10, 10, 50, Color.YELLOW);
        assertEquals(10, c.getXPos());
        assertEquals(10, c.getYPos());

        // Use reflection to check width and height in Ellipse
        Field widthField = Ellipse.class.getDeclaredField("width");
        widthField.setAccessible(true);
        int width = (int) widthField.get(c);

        Field heightField = Ellipse.class.getDeclaredField("height");
        heightField.setAccessible(true);
        int height = (int) heightField.get(c);

        assertEquals(50, width, "Circle width should be diameter");
        assertEquals(50, height, "Circle height should be diameter");
    }
}

